package com.seaquake6324.civitas.infrastructure.network;
import static org.junit.jupiter.api.Assertions.assertEquals;import com.seaquake6324.civitas.domain.population.Gender;import io.netty.buffer.Unpooled;import net.minecraft.core.RegistryAccess;import net.minecraft.network.RegistryFriendlyByteBuf;import org.junit.jupiter.api.Test;
class GenderPayloadTest{@Test void roundTripsSelectionAndResult(){RegistryFriendlyByteBuf b=new RegistryFriendlyByteBuf(Unpooled.buffer(),RegistryAccess.EMPTY);try{var submit=new SubmitGenderSelectionPayload(Gender.FEMALE);SubmitGenderSelectionPayload.STREAM_CODEC.encode(b,submit);assertEquals(submit,SubmitGenderSelectionPayload.STREAM_CODEC.decode(b));b.clear();var result=new GenderSelectionResultPayload(true,"civitas.gender.saved");GenderSelectionResultPayload.STREAM_CODEC.encode(b,result);assertEquals(result,GenderSelectionResultPayload.STREAM_CODEC.decode(b));}finally{b.release();}}}
